    func imageRotation(rotation: String) {
        var strRotation = ""
        if UIDevice.current.orientation == .landscapeRight {
            strRotation = "Right"
        } else if UIDevice.current.orientation == .landscapeLeft {
            strRotation = "Left"
        }
        if rotation == "FrontImg" {
            frontImageRotation = strRotation
        } else if rotation == "BackImg" {
            backImageRotation = strRotation
        } else {
            frontImageRotation = strRotation
        }
    }
    func reco_msg(_ message: String!) {
        var msg = String();
        if(message == ACCURA_ERROR_CODE_MOTION) {
            if accuraErrorCode["ACCURA_ERROR_CODE_MOTION"] != nil{
                msg = accuraErrorCode["ACCURA_ERROR_CODE_MOTION"] as! String
                
            }else{
                msg = "Keep Document Steady";
            }
        } else if(message == ACCURA_ERROR_CODE_DOCUMENT_IN_FRAME) {
            if accuraErrorCode["ACCURA_ERROR_CODE_DOCUMENT_IN_FRAME"] != nil{
                
                msg = accuraErrorCode["ACCURA_ERROR_CODE_DOCUMENT_IN_FRAME"] as! String
                
            }else{
                msg = "Keep document in frame";
            }
        } else if(message == ACCURA_ERROR_CODE_PROCESSING) {
            if accuraErrorCode["ACCURA_ERROR_CODE_PROCESSING"] != nil{
                msg = accuraErrorCode["ACCURA_ERROR_CODE_PROCESSING"] as! String
                
            }else{
                msg = "Processing...";
            }
        } else if(message == ACCURA_ERROR_CODE_MOVE_CLOSER) {
            
          if accuraErrorCode["ACCURA_ERROR_CODE_MOVE_CLOSER"] != nil{
              msg = accuraErrorCode["ACCURA_ERROR_CODE_MOVE_CLOSER"] as! String
              
          }else{
            msg = "Move Phone Closer"
          }
        }else if(message == ACCURA_ERROR_CODE_MOVE_AWAY) {
            
          if accuraErrorCode["ACCURA_ERROR_CODE_MOVE_AWAY"] != nil{
              msg = accuraErrorCode["ACCURA_ERROR_CODE_MOVE_AWAY"] as! String
              
          }else{
            msg = "Move Phone Away"
          }
        }else if(message == ACCURA_ERROR_CODE_KEEP_MICR_IN_FRAME) {
          if accuraErrorCode["ACCURA_ERROR_CODE_KEEP_MICR_IN_FRAME"] != nil{
              msg = accuraErrorCode["ACCURA_ERROR_CODE_KEEP_MICR_IN_FRAME"] as! String
              
          }else{
            msg = "Please Keep MICR in Frame"
          }
        }else {
            msg = message;
        }
        lblOCRMsg.text = msg
    }
    
    
    
    

    
    func date(toFormatedDate dateStr: String?) -> String? {
        let dateFormatter = DateFormatter()
        dateFormatter.dateFormat = "yyMMdd"
        let date: Date? = dateFormatter.date(from: dateStr ?? "")
        dateFormatter.dateFormat = "dd-MM-yy"
        if let date = date {
            return dateFormatter.string(from: date)
        }
        return nil
    }
    
    func date(to dateStr: String?) -> String? {
        // Convert string to date object
        let dateFormat = DateFormatter()
        dateFormat.dateFormat = "yyMMdd"
        let date: Date? = dateFormat.date(from: dateStr ?? "")
        dateFormat.dateFormat = "yy-MM-dd"
        if let date = date {
            return dateFormat.string(from: date)
        }
        return nil
    }
}

extension UIColor {
    convenience init(hexString: String) {
        let hex = hexString.trimmingCharacters(in: CharacterSet.alphanumerics.inverted)
        var int = UInt64()
        Scanner(string: hex).scanHexInt64(&int)
        let a, r, g, b: UInt64
        switch hex.count {
        case 3: // RGB (12-bit)
            (a, r, g, b) = (255, (int >> 8) * 17, (int >> 4 & 0xF) * 17, (int & 0xF) * 17)
        case 6: // RGB (24-bit)
            (a, r, g, b) = (255, int >> 16, int >> 8 & 0xFF, int & 0xFF)
        case 8: // ARGB (32-bit)
            (a, r, g, b) = (int >> 24, int >> 16 & 0xFF, int >> 8 & 0xFF, int & 0xFF)
        default:
            (a, r, g, b) = (255, 0, 0, 0)
        }
        self.init(red: CGFloat(r) / 255, green: CGFloat(g) / 255, blue: CGFloat(b) / 255, alpha: CGFloat(a) / 255)
    }
    
    //MARK:- Custom
    
}

extension UIView {
    
    func addTopBorder(with color: UIColor?, andWidth borderWidth: CGFloat) {
        let border = UIView()
        border.backgroundColor = color
        border.autoresizingMask = [.flexibleWidth, .flexibleBottomMargin]
        border.frame = CGRect(x: 0, y: 0, width: frame.size.width, height: borderWidth)
        addSubview(border)
    }

    func addBottomBorder(with color: UIColor?, andWidth borderWidth: CGFloat) {
        let border = UIView()
        border.backgroundColor = color
        border.autoresizingMask = [.flexibleWidth, .flexibleTopMargin]
        border.frame = CGRect(x: 0, y: frame.size.height - borderWidth, width: frame.size.width, height: borderWidth)
        addSubview(border)
    }

    func addLeftBorder(with color: UIColor?, andWidth borderWidth: CGFloat) {
        let border = UIView()
        border.backgroundColor = color
        border.frame = CGRect(x: 0, y: 0, width: borderWidth, height: frame.size.height)
        border.autoresizingMask = [.flexibleHeight, .flexibleRightMargin]
        addSubview(border)
    }

    func addRightBorder(with color: UIColor?, andWidth borderWidth: CGFloat) {
        let border = UIView()
        border.backgroundColor = color
        border.autoresizingMask = [.flexibleHeight, .flexibleLeftMargin]
        border.frame = CGRect(x: frame.size.width - borderWidth, y: 0, width: borderWidth, height: frame.size.height)
        addSubview(border)
    }
}

